/* Cradling-arc divider — the recurring signature element */
function CradleDivider({ tone = "gold" }) {
  const stroke = tone === "gold" ? "#D6A032" : "#7C9473";
  return (
    <svg viewBox="0 0 200 24" className="w-40 h-6 mx-auto" aria-hidden="true">
      <path
        d="M4 4 C 4 20, 60 20, 100 20 C 140 20, 196 20, 196 4"
        fill="none"
        stroke={stroke}
        strokeWidth="2"
        strokeLinecap="round"
      />
    </svg>
  );
}

function useScrolled() {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 24);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);
  return scrolled;
}

function nextDays(n) {
  const out = [];
  const today = new Date();
  for (let i = 0; i < n; i++) {
    const d = new Date(today);
    d.setDate(today.getDate() + i);
    out.push(d);
  }
  return out;
}

const OPEN_SLOTS = [
  "10:30 AM", "11:00 AM", "11:30 AM", "12:00 PM", "12:30 PM",
  "1:00 PM", "1:30 PM", "2:00 PM", "2:30 PM", "3:00 PM", "3:30 PM",
  "4:00 PM", "4:30 PM", "5:00 PM", "5:30 PM", "6:00 PM", "6:30 PM",
];
function slotsForDate(d) {
  const day = d.getDay(); // 0 = Sunday, 1 = Monday
  if (day === 1) return []; // closed Mondays
  return OPEN_SLOTS;
}

